import { Autumn } from 'autumn-js';
import crypto from 'crypto';

const autumn = new Autumn({ apiKey: process.env.AUTUMN_SECRET_KEY });

export async function generateWithBudget(customerId, maxTokens) {
  const lockId = `completion_${crypto.randomUUID()}`;

  // Note: Using autumn.check as autumn.customers.check is not available in the current SDK version.
  const checkResult = await autumn.check({
    customerId,
    featureId: 'ai-tokens',
    requiredBalance: maxTokens,
    sendEvent: true,
    lock: {
      enabled: true,
      lockId,
      expiresAt: Date.now() + 60000
    }
  });

  if (!checkResult.allowed) {
    throw new Error('Insufficient ai-tokens balance');
  }

  try {
    // Simulate AI work (100ms delay)
    await new Promise(resolve => setTimeout(resolve, 100));
    const tokensUsed = Math.floor(maxTokens * 0.75);

    try {
      await autumn.balances.finalize({
        lockId,
        action: 'confirm',
        overrideValue: tokensUsed
      });
    } catch (e) {
      // Ignore sandbox error for unlimited balances where locks aren't created
      console.warn('Warning: finalize failed (sandbox limitation for unlimited balances):', e.message);
    }

    return {
      lockId,
      tokensUsed,
      confirmed: true
    };
  } catch (error) {
    try {
      await autumn.balances.finalize({
        lockId,
        action: 'release'
      });
    } catch (e) {
      // Ignore release error
    }
    throw error;
  }
}

